class Solution:
    def numberOfStableArrays(self, zero: int, one: int, limit: int) -> int:
        MOD = 10**9 + 7
        @lru_cache(None)
        def dp(z, o, last):
            if z == 0 and o == 0: return 1
            count = 0
            if z > 0 and (last != 0 or z <= limit):
                count = (count + dp(z-1, o, 0)) % MOD
            if o > 0 and (last != 1 or o <= limit):
                count = (count + dp(z, o-1, 1)) % MOD
            return count
        return (dp(zero, one, -1)) % MOD
